import React from 'react';
import { useLocalStorage } from './useLocalStorage';

export default function App() {
  const [count, setCount] = useLocalStorage<number>('demo-count', 0);

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useLocalStorage</h1>
      <p style={{ color: '#6b7280', marginBottom: '1rem' }}>Value persists across page reloads</p>
      <p data-testid="stored-value" style={{ fontSize: '2rem', marginBottom: '1rem' }}>{count}</p>
      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button data-testid="increment" onClick={() => setCount(count + 1)}>Increment</button>
        <button data-testid="reset" onClick={() => setCount(0)}>Reset</button>
      </div>
    </div>
  );
}

import { useState } from 'react';

/**
 * Custom hook that syncs state with localStorage.
 *
 * @param key - The localStorage key
 * @param initialValue - Fallback value if nothing is stored
 * @returns [storedValue, setValue]
 */
export function useLocalStorage<T>(
  key: string,
  initialValue: T
): [T, (value: T | ((prev: T) => T)) => void] {
  // TODO: Read from localStorage on mount (with JSON.parse)
  // TODO: Return [value, setter that writes to both state and localStorage]

  return [initialValue, () => {}];
}

