import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useLocalStorage } from './useLocalStorage';

function Harness({ storageKey = 'test-key', initial = 0 }: { storageKey?: string; initial?: number }) {
  const [value, setValue] = useLocalStorage<number>(storageKey, initial);
  return (
    <div>
      <span data-testid="stored-value">{value}</span>
      <button data-testid="increment" onClick={() => setValue(value + 1)}>+</button>
      <button data-testid="reset" onClick={() => setValue(0)}>Reset</button>
    </div>
  );
}

describe('useLocalStorage', () => {
  beforeEach(() => localStorage.clear());

  it('uses initial value when nothing is stored', () => {
    render(<Harness initial={42} />);
    expect(screen.getByTestId('stored-value')).toHaveTextContent('42');
  });

  it('reads existing value from localStorage', () => {
    localStorage.setItem('test-key', JSON.stringify(99));
    render(<Harness />);
    expect(screen.getByTestId('stored-value')).toHaveTextContent('99');
  });

  it('writes to localStorage on update', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('increment'));
    expect(JSON.parse(localStorage.getItem('test-key') || '0')).toBe(1);
  });

  it('updates displayed value on set', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    expect(screen.getByTestId('stored-value')).toHaveTextContent('2');
  });

  it('falls back to initial on corrupt data', () => {
    localStorage.setItem('test-key', '{{{bad json');
    render(<Harness initial={5} />);
    expect(screen.getByTestId('stored-value')).toHaveTextContent('5');
  });

  it('can reset to initial value', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('increment'));
    fireEvent.click(screen.getByTestId('reset'));
    expect(screen.getByTestId('stored-value')).toHaveTextContent('0');
    expect(JSON.parse(localStorage.getItem('test-key') || '-1')).toBe(0);
  });
});

